const fileVarId = '4a2f3061-67ff-4b46-ae5d-13029c7d6875-value';

const raw = context.component?.variables?.[fileVarId];
const file = Array.isArray(raw) ? raw[0] : raw;

if (!file) {
  throw new Error('Файл не найден');
}

const originalName = file.name || 'file';

const map = {
  'А': 'A', 'а': 'a',
  'Б': 'B', 'б': 'b',
  'В': 'V', 'в': 'v',
  'Г': 'G', 'г': 'g',
  'Д': 'D', 'д': 'd',
  'Е': 'E', 'е': 'e',
  'Ё': 'Yo', 'ё': 'yo',
  'Ж': 'Zh', 'ж': 'zh',
  'З': 'Z', 'з': 'z',
  'И': 'I', 'и': 'i',
  'Й': 'Y', 'й': 'y',
  'К': 'K', 'к': 'k',
  'Л': 'L', 'л': 'l',
  'М': 'M', 'м': 'm',
  'Н': 'N', 'н': 'n',
  'О': 'O', 'о': 'o',
  'П': 'P', 'п': 'p',
  'Р': 'R', 'р': 'r',
  'С': 'S', 'с': 's',
  'Т': 'T', 'т': 't',
  'У': 'U', 'у': 'u',
  'Ф': 'F', 'ф': 'f',
  'Х': 'Kh', 'х': 'kh',
  'Ц': 'Ts', 'ц': 'ts',
  'Ч': 'Ch', 'ч': 'ch',
  'Ш': 'Sh', 'ш': 'sh',
  'Щ': 'Shch', 'щ': 'shch',
  'Ъ': '', 'ъ': '',
  'Ы': 'Y', 'ы': 'y',
  'Ь': '', 'ь': '',
  'Э': 'E', 'э': 'e',
  'Ю': 'Yu', 'ю': 'yu',
  'Я': 'Ya', 'я': 'ya',
};

function translit(text = '') {
  return String(text)
    .split('')
    .map(ch => map[ch] ?? ch)
    .join('');
}

function randomString(length = 3) {
  const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
  return Array.from({ length }, () => chars[Math.floor(Math.random() * chars.length)]).join('');
}

let transliteratedName = translit(originalName)
  .normalize('NFKD')
  .replace(/[\u0300-\u036f]/g, '')
  .trim()
  .replace(/\s+/g, '-');

const ext = (originalName.split('.').pop() || '').toLowerCase();
const baseName = `${randomString()}_${transliteratedName.replace(/\.[^.]+$/, '')}`;
const finalName = `${baseName}.${ext}`;

const renamedFile = new File([file], finalName, { type: file.type });

return {
  file: renamedFile,
  finalName,
  originalName,
  sizeBefore: file.size,
  sizeAfter: file.size,
  type: file.type,
};
